function makeUuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const item = $json;
const fullText = item.full_text || '';

// Parse manager from title line
const managerMatch = fullText.match(/\[WMMA\]\s*(.*?)\s+Weekly Manager Meeting/i);
const manager_name = managerMatch ? managerMatch[1].trim() : null;

// Parse meeting date from first line if possible
const firstLine = fullText.split('\n')[0]?.trim();
let meetingDate = new Date(firstLine);

if (isNaN(meetingDate.getTime())) {
  meetingDate = new Date();
}

// Set meeting datetime
const meeting_datetime = meetingDate.toISOString().slice(0, 19).replace('T', ' ');

// Derive Monday week reference
const d = new Date(meetingDate);
const day = d.getDay();
const diff = d.getDate() - day + (day === 0 ? -6 : 1);
const monday = new Date(d.setDate(diff)).toISOString().slice(0, 10);

const created_at = new Date().toISOString().slice(0, 19).replace('T', ' ');

return [{
  json: {
    id: makeUuid(),
    drive_file_id: item.drive_file_id,
    manager_name,
    meeting_datetime,
    week_reference: monday,
    transcript_raw: null,
    full_text: item.full_text,
    summary_structured: item.summary_structured,
    actions: item.actions,
    created_at
  }
}];

const doc = $json;

let fullText = '';

for (const el of doc.body?.content || []) {
  if (el.paragraph?.elements) {
    for (const pe of el.paragraph.elements) {
      if (pe.textRun?.content) {
        fullText += pe.textRun.content;
      }
    }
  }
}

// Normalize
fullText = fullText.replace(/\r/g, '').trim();

// Split sections
function extractSection(text, start, endMarkers) {
  const startIndex = text.indexOf(start);
  if (startIndex === -1) return '';

  let endIndex = text.length;

  for (const marker of endMarkers) {
    const idx = text.indexOf(marker, startIndex + start.length);
    if (idx !== -1 && idx < endIndex) {
      endIndex = idx;
    }
  }

  return text.substring(startIndex + start.length, endIndex).trim();
}

// Normalize owner names to contract-safe values
function normalizeOwner(owner) {
  const v = String(owner || '').trim().toLowerCase();

  if (v === 'brandon stewart' || v === 'brandon') return 'Brandon';
  if (v === 'breanna blanks' || v === 'breanna' || v === 'brianna blanks' || v === 'brianna') return 'Breanna';

  return String(owner || '').trim();
}

// Detect property from action text
const knownProperties = [
  'Adobe',
  'NorthPark',
  'Courtyard',
  'Jefferson',
  'Riveredge',
  'Crosskeys',
  'Sagebrush',
  'Westminster',
  'Broadstone',
  'Nelson',
  'Oak Terrace',
  'Single Families and Small Multi'
];

function detectProperty(text) {
  for (const property of knownProperties) {
    const re = new RegExp(`\\b${property.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b`, 'i');
    if (re.test(text)) return property;
  }
  return null;
}

const portfolioPerformance = extractSection(fullText, 'Portfolio Performance', [
  'Operational Issues',
  'Decisions',
  'Next steps'
]);

const issues = extractSection(fullText, 'Operational Issues', [
  'Decisions',
  'Next steps'
]);

const decisions = extractSection(fullText, 'Decisions', [
  'Next steps'
]);

const nextSteps = extractSection(fullText, 'Next steps', []);

// Extract actions
const actionLines = nextSteps
  .split('\n')
  .map(l => l.trim())
  .filter(l => l.startsWith('[') && l.includes(']') && l.includes(':'));

const actions = actionLines.map(line => {
  const match = line.match(/^\[(.*?)\]\s*(.*?):\s*(.*)$/);

  if (!match) return null;

  const rawOwner = match[1].trim();
  const title = match[2].trim();
  const detail = match[3].trim();

  const owner = normalizeOwner(rawOwner);
  const description = `${title}: ${detail}`;

  const dueMatch = detail.match(/(\d{4}-\d{2}-\d{2})/);
  const property_name = detectProperty(`${title} ${detail}`);

  return {
    description,
    owner,
    due_date: dueMatch ? dueMatch[1] : null,
    property_name
  };
}).filter(Boolean);

return [{
  json: {
    drive_file_id: doc.documentId,
    full_text: fullText,
    summary_structured: {
      changes: portfolioPerformance ? [portfolioPerformance] : [],
      issues: issues ? [issues] : [],
      decisions: decisions ? [decisions] : []
    },
    actions
  }
}];

if (!$json.full_text || !String($json.full_text).trim()) {
  throw new Error('Missing full_text');
}

if (!$json.manager_name || !String($json.manager_name).trim()) {
  throw new Error('Manager name not parsed');
}

if (!$json.meeting_datetime) {
  throw new Error('Missing meeting_datetime');
}

if (!$json.week_reference) {
  throw new Error('Missing week_reference');
}

if (
  !$json.summary_structured ||
  !Array.isArray($json.summary_structured.changes) ||
  !Array.isArray($json.summary_structured.issues) ||
  !Array.isArray($json.summary_structured.decisions)
) {
  throw new Error('Invalid summary_structured shape');
}

if (!Array.isArray($json.actions)) {
  throw new Error('Invalid actions array');
}

if ($json.actions.length < 1 || $json.actions.length > 5) {
  throw new Error(`Expected 1-5 actions, got ${$json.actions.length}`);
}

return [{ json: $json }];

